	('adc9d95e-349c-4bdd-b699-ce8b4c9911bf', 'BE – Mechanical Engineering', 'knowledge', NULL, '[{"id": 1, "text": "Which of the following materials is commonly used in gears due to its high wear resistance?", "type": "mcq", "uuid": "4ec2c15d-0e48-45fc-a7ef-26fb235df955", "correct": "C", "options": ["A. Aluminum", "B. Copper", "C. Steel", "D. Wood"], "question": "Which of the following materials is commonly used in gears due to its high wear resistance?", "skill_tag": "Materials in Mechanical Engineering", "stream_id": "BE – Mechanical Engineering", "created_at": "2026-03-30T05:57:14.136Z", "difficulty": "easy", "stream_name": "BE – Mechanical Engineering", "correct_answer": "C. Steel"}, {"id": 2, "text": "What is the primary function of a flywheel in an engine system?", "type": "mcq", "uuid": "245f3b79-5afd-4c25-97b5-1ec38c822935", "correct": "B", "options": ["A. To store electrical energy", "B. To provide rotational inertia", "C. To filter exhaust gases", "D. To cool the engine"], "question": "What is the primary function of a flywheel in an engine system?", "skill_tag": "Engine Systems", "stream_id": "BE – Mechanical Engineering", "created_at": "2026-03-30T05:57:14.136Z", "difficulty": "easy", "stream_name": "BE – Mechanical Engineering", "correct_answer": "B. To provide rotational inertia"}, {"id": 3, "text": "Which law of thermodynamics states that energy can neither be created nor destroyed?", "type": "mcq", "uuid": "4f44d6f5-ef1a-4456-aea8-5f629ac64d03", "correct": "B", "options": ["A. Zeroth Law", "B. First Law", "C. Second Law", "D. Third Law"], "question": "Which law of thermodynamics states that energy can neither be created nor destroyed?", "skill_tag": "Thermodynamics", "stream_id": "BE – Mechanical Engineering", "created_at": "2026-03-30T05:57:14.136Z", "difficulty": "medium", "stream_name": "BE – Mechanical Engineering", "correct_answer": "B. First Law"}, {"id": 4, "text": "In fluid mechanics, what does the Reynolds number describe?", "type": "mcq", "uui